import React from 'react';

export default function AvatarGroup({ users, max = 4 }) {
  const visibleUsers = users.slice(0, max);
  const overflowCount = users.length - max;

  return (
    <div className="flex -space-x-3 items-center select-none">
      {visibleUsers.map((user, idx) => (
        <div key={user.id || idx} className="relative group">
          <img
            className="w-10 h-10 rounded-full border-2 border-white dark:border-gray-900 object-cover"
            src={user.avatarUrl}
            alt={user.name}
          />
          {user.status && (
            <span className={`absolute bottom-0 right-0 block h-2.5 w-2.5 rounded-full border-2 border-white dark:border-gray-900 ${
              user.status === 'online' ? 'bg-green-400' : 'bg-gray-400'
            }`} />
          )}
          {/* Tooltip */}
          <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 hidden group-hover:block bg-zinc-800 text-white text-xs rounded px-2 py-1 whitespace-nowrap shadow-md z-30">
            {user.name}
          </div>
        </div>
      ))}
      {overflowCount > 0 && (
        <div className="relative flex items-center justify-center w-10 h-10 rounded-full border-2 border-white dark:border-gray-900 bg-gray-100 dark:bg-gray-800 text-xs font-semibold text-gray-600 dark:text-gray-300">
          +{overflowCount}
        </div>
      )}
    </div>
  );
}
